function getDisplayFocusArea(focusArea) {
  if (!focusArea) return 'Status & Visas';
  const f = focusArea.toLowerCase();
  if (f.includes('visa') || f === 'status') return 'Status & Visas';
  if (f.includes('job') || f.includes('career')) return 'Career & Jobs';
  if (f.includes('credit') || f === 'finance') return 'Finance & Credit';
  return 'Status & Visas';
}

function isSessionCompleted(dateStr, timeStr) {
  try {
    const parts = timeStr.split('-');
    if (parts.length < 2) return false;
    let endTimePart = parts[1].trim();
    endTimePart = endTimePart.split('(')[0].trim();

    const endDateTimeStr = `${dateStr} ${endTimePart}`;
    const endDate = new Date(endDateTimeStr);

    if (isNaN(endDate.getTime())) {
      console.warn("Invalid date parsed:", endDateTimeStr);
      return false;
    }

    const now = new Date();
    return now >= endDate;
  } catch (e) {
    console.error("Error in isSessionCompleted:", e);
    return false;
  }
}

